import React, { useCallback, useEffect, useRef, useState } from 'react';
import { connect } from 'react-redux';
import { useNavigate } from 'react-router-dom';

import { setServerFeatureNotReadyYet, setPositionInfo, setShowMenu } from '../../../reduxStore/actions/flowActions';
import { setOnBoardingModalsVisibility, setOnBoardingVisible } from '../../../reduxStore/actions/modalsActions';
import CompanyOrganizationalChart from './CompanyOrganizationalChart';
import cls from './EditComOrgChart.module.scss';
import { Button, PermissionWrapper, Spinner, po } from '../../common';
import { getPositionById } from '../../../services/company.service';
import { store } from '../../../reduxStore/store';
import CreateDepartments from '../OnboardingModals/CreateDepartments';
const EditComOrgChart = props => {
	const navigate = useNavigate();
	const { onToggleModalVisibility, onSetOnBoardingVisible, companyOrgChart } = props;
	const [departments] = useState({});
	const [aContainerDim, setAContainerDim] = useState({ width: 0, height: 0 });
	const aContainerRef = useRef();
	const [showDepartments, setShowDepartments] = useState(false);
	const [loading, setLoading] = useState(false);
	const [showAsChart, setShowAsChart] = useState(false);
	useEffect(() => {
		setAContainerDimensions();
	}, [aContainerRef, departments]);
	const setAContainerDimensions = useCallback(() => {
		const { width, height } = aContainerRef?.current?.getBoundingClientRect() || {};
		setAContainerDim({ width: width, height: height });
	}, [aContainerRef]);

	const onPositionPressed = positionId => {
		setLoading(true);
		getPositionById(positionId).subscribe({
			next: () => {
				setLoading(false);
				onToggleModalVisibility({ positionModalVisible: true });
				onSetOnBoardingVisible(true);
			},
			error: () => {
				setLoading(false);
			},
			complete: () => {},
		});
	};

	return (
		<div className={cls.mainContainer}>
			<div className={cls.backButtonContainer} style={{ display: '' }}>
				<Button
					title={'Back'}
					clicked={() => {
						store.dispatch(setShowMenu(true));
						navigate('/company');
					}}
				></Button>
				<PermissionWrapper permissions={[po.company.orgChart.update]}>
					<Button
						light
						title={'Departments'}
						clicked={() => {
							setShowDepartments(true);
						}}
					/>
					<Button
						light
						title={'Add Role'}
						clicked={() => {
							store.dispatch(
								setPositionInfo({
									name: '',
									id: '',
									parent: undefined,
									parent_position: undefined,
									department_id: '',
									is_managerial: false,
									children: [],
									users: [],
									shared_users: [],
								})
							);
							onToggleModalVisibility({ positionModalVisible: true });
							onSetOnBoardingVisible(true);
						}}
					/>
					<Button
						light
						title={showAsChart ? 'View List' : 'View Chart'}
						clicked={() => {
							setShowAsChart(!showAsChart);
						}}
					/>
				</PermissionWrapper>
			</div>
			<div className={cls.paragraphNameContainer}>
				<Button title={'Roles and Departments'} clear loading={loading} />
			</div>

			<div ref={aContainerRef} className={cls.chartContainer}>
				<CompanyOrganizationalChart dimmensions={aContainerDim} onPositionPressed={onPositionPressed} showAsChart={showAsChart}></CompanyOrganizationalChart>
			</div>

			{showDepartments && (
				<CreateDepartments
					modalVisible={showDepartments}
					hasCloseButton={true}
					modalWrapperStyle={{}}
					shadowedContainerStyle={{ minWidth: '523px', width: '40%', height: 'auto' }}
					childrenWrapperStyle={{}}
					onCancel={() => {
						setShowDepartments(false);
					}}
					onPreviousButtonAction={() => {
						setShowDepartments(false);
					}}
					onNextButtonAction={() => {
						setShowDepartments(false);
					}}
				/>
			)}
		</div>
	);
};

const mapStateToProps = store => {
	const { inviteColleguesList, companyOrgChart } = store.flowReducer;
	return { inviteColleguesList, companyOrgChart };
};
const mapDispatchToProps = dispatch => {
	return {
		onSetOnBoardingVisible: visible => dispatch(setOnBoardingVisible(visible)),
		onToggleModalVisibility: modalVisible => dispatch(setOnBoardingModalsVisibility(modalVisible)),
		onSetServerFeatureNotReadyYet: unlock => dispatch(setServerFeatureNotReadyYet(unlock)),
	};
};
export default connect(mapStateToProps, mapDispatchToProps)(EditComOrgChart);
